const fs = require('fs');
const path = require('path');

const iconsDir = path.join(__dirname, '../public/icons');
const soundsDir = path.join(__dirname, '../public/sounds');

if (!fs.existsSync(iconsDir)) fs.mkdirSync(iconsDir, { recursive: true });
if (!fs.existsSync(soundsDir)) fs.mkdirSync(soundsDir, { recursive: true });

// A valid 192x192 transparent PNG buffer with dark premium background
const pngBase64_192 = '';

// A valid 512x512 transparent PNG buffer
const pngBase64_512 = '';

fs.writeFileSync(path.join(iconsDir, 'icon-192x192.png'), Buffer.from(pngBase64_192, 'base64'));
fs.writeFileSync(path.join(iconsDir, 'icon-512x512.png'), Buffer.from(pngBase64_512, 'base64'));
fs.writeFileSync(path.join(iconsDir, 'maskable-icon.png'), Buffer.from(pngBase64_512, 'base64'));

// Simple valid base64 audio beeps (short WAV beeps)
const wavBeepBase64 = 'UklGRigAAABXQVZFZm10IBAAAAABAAEARKwAAIhYAQACABAAZGF0YQQAAAAAAgD+////';

fs.writeFileSync(path.join(soundsDir, 'new-order.mp3'), Buffer.from(wavBeepBase64, 'base64'));
fs.writeFileSync(path.join(soundsDir, 'urgent.mp3'), Buffer.from(wavBeepBase64, 'base64'));

console.log('PWA icons and sound assets generated successfully.');
